#:property AllowUnsafeBlocks=true

Console.WriteLine("Testing stackalloc Span<nint>...");

Span<nint> span = stackalloc nint[5];
for (int i = 0; i < span.Length; i++)
    span[i] = (nint)(i * 10);

Console.WriteLine($"Span length: {span.Length}");
Console.WriteLine($"Element size: {sizeof(nint)} bytes (native int)");
for (int i = 0; i < span.Length; i++)
    Console.WriteLine($"  span[{i}] = {span[i]}");

Console.WriteLine("\nTesting stackalloc Span<nuint>...");
Span<nuint> uspan = stackalloc nuint[3];
for (int i = 0; i < uspan.Length; i++)
    uspan[i] = (nuint)(i * 100);

for (int i = 0; i < uspan.Length; i++)
    Console.WriteLine($"  uspan[{i}] = {uspan[i]}");

Console.WriteLine("\nSuccess! stackalloc with nint/nuint works.");

